-- ============================================================================
-- Quiz Seed: 1 Timothy (Chapters 1–6)
-- 3 difficulties × 6 chapters = 96 total questions
--   kids:   3 per chapter  = 18
--   teens:  5 per chapter  = 30
--   adults: 8 per chapter  = 48
-- ============================================================================

-- ═══ 1 Timothy Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Timothy', 1, 'kids', 1, 'Who wrote this letter?', 'Paul', 'Peter', 'James', 'John', 'a', '1 Timothy 1:1 — "Paul, an apostle of Jesus Christ by the commandment of God our Saviour."'),
('1 Timothy', 1, 'kids', 2, 'What did Paul call Timothy?', 'His own son in the faith', 'His brother', 'His teacher', 'His servant', 'a', '1 Timothy 1:2 — "Unto Timothy, my own son in the faith."'),
('1 Timothy', 1, 'kids', 3, 'What did Paul say Jesus came into the world to do?', 'Save sinners', 'Build a temple', 'Start a school', 'Become a king', 'a', '1 Timothy 1:15 — "Christ Jesus came into the world to save sinners."'),
-- Teens
('1 Timothy', 1, 'teens', 1, 'What did Paul charge Timothy to do at Ephesus?', 'Command certain men not to teach other doctrine or give heed to fables and genealogies', 'Collect money for the temple in Jerusalem', 'Organize a council of all the apostles', 'Build a new synagogue for the church', 'a', '1 Timothy 1:3-4 — "That thou mightest charge some that they teach no other doctrine, Neither give heed to fables and endless genealogies."'),
('1 Timothy', 1, 'teens', 2, 'What is the end (goal) of the commandment?', 'Charity out of a pure heart, and of a good conscience, and of faith unfeigned', 'Strict obedience to every rule', 'Knowledge of all theological mysteries', 'Perfect performance of rituals', 'a', '1 Timothy 1:5 — "Now the end of the commandment is charity out of a pure heart, and of a good conscience, and of faith unfeigned."'),
('1 Timothy', 1, 'teens', 3, 'Who is the law made for according to Paul?', 'Not for a righteous man, but for the lawless and disobedient, ungodly and sinners', 'Only for the Jewish people', 'For church leaders exclusively', 'For everyone without exception', 'a', '1 Timothy 1:9 — "Knowing this, that the law is not made for a righteous man, but for the lawless and disobedient, for the ungodly and for sinners."'),
('1 Timothy', 1, 'teens', 4, 'What does Paul call himself in relation to sinners?', 'The chief of sinners', 'The holiest apostle', 'The wisest teacher', 'The bravest warrior', 'a', '1 Timothy 1:15 — "Christ Jesus came into the world to save sinners; of whom I am chief."'),
('1 Timothy', 1, 'teens', 5, 'What happened to Hymenaeus and Alexander?', 'Paul delivered them unto Satan, that they may learn not to blaspheme', 'They were promoted to elders', 'They were sent on missionary trips', 'They became Paul''s closest companions', 'a', '1 Timothy 1:20 — "Of whom is Hymenæus and Alexander; whom I have delivered unto Satan, that they may learn not to blaspheme."'),
-- Adults
('1 Timothy', 1, 'adults', 1, 'What does Paul say some have turned aside unto?', 'Vain jangling — wanting to be teachers of the law without understanding what they say or affirm', 'Genuine theological inquiry', 'Profitable charitable works', 'Effective missionary strategies', 'a', '1 Timothy 1:6-7 — "From which some having swerved have turned aside unto vain jangling; Desiring to be teachers of the law; understanding neither what they say, nor whereof they affirm."'),
('1 Timothy', 1, 'adults', 2, 'What does Paul say about the law in verse 8?', 'The law is good, if a man use it lawfully', 'The law has been entirely abolished', 'The law is evil and should be rejected', 'The law is only for Israel and not the church', 'a', '1 Timothy 1:8 — "But we know that the law is good, if a man use it lawfully."'),
('1 Timothy', 1, 'adults', 3, 'What does Paul call the gospel he was entrusted with?', 'The glorious gospel of the blessed God, which was committed to his trust', 'The law of Moses updated for Gentiles', 'The wisdom of Greek philosophy', 'The traditions of the Jewish elders', 'a', '1 Timothy 1:11 — "According to the glorious gospel of the blessed God, which was committed to my trust."'),
('1 Timothy', 1, 'adults', 4, 'What was Paul before Christ showed him mercy?', 'A blasphemer, a persecutor, and injurious — but he obtained mercy because he did it ignorantly in unbelief', 'A faithful Pharisee who always obeyed God', 'A Roman soldier who fought for justice', 'A Greek philosopher who sought truth', 'a', '1 Timothy 1:13 — "Who was before a blasphemer, and a persecutor, and injurious: but I obtained mercy, because I did it ignorantly in unbelief."'),
('1 Timothy', 1, 'adults', 5, 'What does Paul call the statement "Christ Jesus came into the world to save sinners"?', 'A faithful saying and worthy of all acceptation', 'An interesting theory worth considering', 'A metaphor not to be taken literally', 'A teaching only for advanced believers', 'a', '1 Timothy 1:15 — "This is a faithful saying, and worthy of all acceptation, that Christ Jesus came into the world to save sinners."'),
('1 Timothy', 1, 'adults', 6, 'Why did Paul obtain mercy as the chief of sinners?', 'That in him first Jesus Christ might shew forth all longsuffering, for a pattern to them which should believe on him to life everlasting', 'Because Paul''s sins were not very serious', 'Because Paul was from a good family', 'Because Paul had already done many good works', 'a', '1 Timothy 1:16 — "Howbeit for this cause I obtained mercy, that in me first Jesus Christ might shew forth all longsuffering, for a pattern to them which should hereafter believe on him to life everlasting."'),
('1 Timothy', 1, 'adults', 7, 'What doxology does Paul give in verse 17?', 'Now unto the King eternal, immortal, invisible, the only wise God, be honour and glory for ever and ever', 'Blessed be the God and Father of our Lord Jesus Christ', 'Great is the Lord and greatly to be praised', 'Holy, holy, holy, Lord God Almighty', 'a', '1 Timothy 1:17 — "Now unto the King eternal, immortal, invisible, the only wise God, be honour and glory for ever and ever. Amen."'),
('1 Timothy', 1, 'adults', 8, 'What charge does Paul give Timothy in verse 18?', 'War a good warfare, holding faith and a good conscience', 'Build a large and wealthy church', 'Travel to as many cities as possible', 'Write many letters to the churches', 'a', '1 Timothy 1:18 — "This charge I commit unto thee, son Timothy... that thou by them mightest war a good warfare; Holding faith, and a good conscience."');

-- ═══ 1 Timothy Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Timothy', 2, 'kids', 1, 'What does Paul say we should do for all people?', 'Pray for them', 'Ignore them', 'Judge them', 'Compete with them', 'a', '1 Timothy 2:1 — "I exhort therefore, that, first of all, supplications, prayers, intercessions, and giving of thanks, be made for all men."'),
('1 Timothy', 2, 'kids', 2, 'How many Gods are there?', 'One God', 'Many gods', 'Two gods', 'No one knows', 'a', '1 Timothy 2:5 — "For there is one God."'),
('1 Timothy', 2, 'kids', 3, 'Who is the one person who connects God and people?', 'The man Christ Jesus', 'Moses', 'Abraham', 'King David', 'a', '1 Timothy 2:5 — "There is one God, and one mediator between God and men, the man Christ Jesus."'),
-- Teens
('1 Timothy', 2, 'teens', 1, 'Why should we pray for kings and those in authority?', 'That we may lead a quiet and peaceable life in all godliness and honesty', 'So they will make us wealthy', 'So they will join our church', 'So they will stop all wars', 'a', '1 Timothy 2:2 — "For kings, and for all that are in authority; that we may lead a quiet and peaceable life in all godliness and honesty."'),
('1 Timothy', 2, 'teens', 2, 'What does God desire for all men?', 'That all men be saved and come unto the knowledge of the truth', 'That all men become priests', 'That all men move to Jerusalem', 'That all men become wealthy', 'a', '1 Timothy 2:4 — "Who will have all men to be saved, and to come unto the knowledge of the truth."'),
('1 Timothy', 2, 'teens', 3, 'What did Christ give himself as?', 'A ransom for all, to be testified in due time', 'A gift only for the Jewish nation', 'A sacrifice only for the apostles', 'An example only for church leaders', 'a', '1 Timothy 2:6 — "Who gave himself a ransom for all, to be testified in due time."'),
('1 Timothy', 2, 'teens', 4, 'How does Paul say men should pray?', 'Lifting up holy hands, without wrath and doubting', 'With loud voices and dramatic gestures', 'Only in the synagogue on the Sabbath', 'Silently and never out loud', 'a', '1 Timothy 2:8 — "I will therefore that men pray every where, lifting up holy hands, without wrath and doubting."'),
('1 Timothy', 2, 'teens', 5, 'How does Paul say women should adorn themselves?', 'In modest apparel, with shamefacedness and sobriety; with good works', 'With gold, pearls, and costly array', 'With the latest fashions of Rome', 'With nothing special at all', 'a', '1 Timothy 2:9-10 — "That women adorn themselves in modest apparel, with shamefacedness and sobriety; not with broided hair, or gold, or pearls, or costly array; But (which becometh women professing godliness) with good works."'),
-- Adults
('1 Timothy', 2, 'adults', 1, 'What four types of prayer does Paul list in verse 1?', 'Supplications, prayers, intercessions, and giving of thanks', 'Praise, worship, singing, and dancing', 'Fasting, mourning, weeping, and groaning', 'Reading, studying, meditating, and memorizing', 'a', '1 Timothy 2:1 — "I exhort therefore, that, first of all, supplications, prayers, intercessions, and giving of thanks, be made for all men."'),
('1 Timothy', 2, 'adults', 2, 'What is good and acceptable in the sight of God our Saviour?', 'Praying for all men, including kings and those in authority', 'Building large and impressive temples', 'Accumulating great theological knowledge', 'Performing signs and wonders', 'a', '1 Timothy 2:3 — "For this is good and acceptable in the sight of God our Saviour."'),
('1 Timothy', 2, 'adults', 3, 'What is the theological significance of "one mediator between God and men, the man Christ Jesus"?', 'Christ alone bridges the gap between God and humanity — no other mediator, priest, or intercessor is needed', 'There are many mediators but Christ is the chief', 'Moses was the mediator of the Old Testament and Christ of the New', 'The term mediator refers to Christ''s role as teacher', 'a', '1 Timothy 2:5 — "For there is one God, and one mediator between God and men, the man Christ Jesus." The singular "one" excludes all other mediators.'),
('1 Timothy', 2, 'adults', 4, 'What does Paul say he was ordained as?', 'A preacher, and an apostle, and a teacher of the Gentiles in faith and verity', 'A priest of the temple in Jerusalem', 'A judge over the twelve tribes', 'A governor of the churches', 'a', '1 Timothy 2:7 — "Whereunto I am ordained a preacher, and an apostle, (I speak the truth in Christ, and lie not;) a teacher of the Gentiles in faith and verity."'),
('1 Timothy', 2, 'adults', 5, 'What does Paul say about Adam and Eve regarding the order of creation?', 'Adam was first formed, then Eve', 'Eve was formed first, then Adam', 'They were formed at the same time', 'The order of creation is not mentioned', 'a', '1 Timothy 2:13 — "For Adam was first formed, then Eve."'),
('1 Timothy', 2, 'adults', 6, 'Who was in the transgression according to verse 14?', 'Adam was not deceived, but the woman being deceived was in the transgression', 'Adam was deceived first', 'Both were equally deceived', 'Neither was truly deceived', 'a', '1 Timothy 2:14 — "And Adam was not deceived, but the woman being deceived was in the transgression."'),
('1 Timothy', 2, 'adults', 7, 'What does Paul say about women being saved through childbearing?', 'She shall be saved in childbearing, if they continue in faith and charity and holiness with sobriety', 'Childbearing is the means of spiritual salvation', 'Women are exempt from salvation requirements', 'Childbearing is forbidden for godly women', 'a', '1 Timothy 2:15 — "Notwithstanding she shall be saved in childbearing, if they continue in faith and charity and holiness with sobriety."'),
('1 Timothy', 2, 'adults', 8, 'What does Paul emphasize by saying "I speak the truth in Christ, and lie not" in verse 7?', 'He solemnly affirms the truth of his apostolic appointment, especially regarding his mission to the Gentiles', 'He is making a casual remark', 'He is quoting an Old Testament prophecy', 'He is defending himself against a specific false charge', 'a', '1 Timothy 2:7 — "I speak the truth in Christ, and lie not." Paul uses this emphatic assertion to validate his divine appointment as apostle to the Gentiles.');

-- ═══ 1 Timothy Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Timothy', 3, 'kids', 1, 'What kind of person should a bishop (church leader) be?', 'Blameless and of good behaviour', 'The richest person in town', 'The tallest and strongest man', 'Someone with the loudest voice', 'a', '1 Timothy 3:2 — "A bishop then must be blameless, the husband of one wife, vigilant, sober, of good behaviour."'),
('1 Timothy', 3, 'kids', 2, 'What kind of people should deacons (church helpers) be?', 'Honest and serious', 'The funniest and most popular', 'The youngest in the church', 'Only people with no family', 'a', '1 Timothy 3:8 — "Likewise must the deacons be grave, not doubletongued, not given to much wine, not greedy of filthy lucre."'),
('1 Timothy', 3, 'kids', 3, 'What does Paul call the church?', 'The pillar and ground of the truth', 'A building made of gold', 'A castle in the clouds', 'A school for smart people', 'a', '1 Timothy 3:15 — "The church of the living God, the pillar and ground of the truth."'),
-- Teens
('1 Timothy', 3, 'teens', 1, 'What does Paul say about desiring the office of a bishop?', 'He desireth a good work — it is a true saying', 'It is prideful and should be avoided', 'Only apostles should seek this office', 'It is reserved for the wealthy', 'a', '1 Timothy 3:1 — "This is a true saying, If a man desire the office of a bishop, he desireth a good work."'),
('1 Timothy', 3, 'teens', 2, 'Why must a bishop not be a novice (new convert)?', 'Lest being lifted up with pride he fall into the condemnation of the devil', 'Because new converts are too enthusiastic', 'Because they have not paid enough dues', 'Because they don''t know enough people', 'a', '1 Timothy 3:6 — "Not a novice, lest being lifted up with pride he fall into the condemnation of the devil."'),
('1 Timothy', 3, 'teens', 3, 'What must a bishop have from those outside the church?', 'A good report of them which are without', 'A letter of recommendation from the government', 'Approval from the Jewish council', 'Endorsement from other bishops', 'a', '1 Timothy 3:7 — "Moreover he must have a good report of them which are without; lest he fall into reproach and the snare of the devil."'),
('1 Timothy', 3, 'teens', 4, 'What must deacons be proved (tested) before doing?', 'Let them first be proved; then let them use the office of a deacon, being found blameless', 'They need no testing if they volunteer', 'They only need to pass a written exam', 'They must serve for ten years first', 'a', '1 Timothy 3:10 — "And let these also first be proved; then let them use the office of a deacon, being found blameless."'),
('1 Timothy', 3, 'teens', 5, 'What great mystery does Paul mention at the end of the chapter?', 'Great is the mystery of godliness: God was manifest in the flesh', 'The mystery of why evil exists', 'The mystery of the end times', 'The mystery of speaking in tongues', 'a', '1 Timothy 3:16 — "And without controversy great is the mystery of godliness: God was manifest in the flesh."'),
-- Adults
('1 Timothy', 3, 'adults', 1, 'What does Paul say a bishop must be the husband of?', 'One wife — "mias gunaikos andra" meaning a one-woman man', 'No wife — he must be celibate', 'Multiple wives to show he can manage a household', 'A wife from a priestly family', 'a', '1 Timothy 3:2 — "A bishop then must be blameless, the husband of one wife."'),
('1 Timothy', 3, 'adults', 2, 'What is the connection Paul draws between managing a household and leading the church?', 'If a man know not how to rule his own house, how shall he take care of the church of God?', 'Managing a household is irrelevant to church leadership', 'Only unmarried men can focus properly on the church', 'Church leadership requires different skills than family leadership', 'a', '1 Timothy 3:5 — "For if a man know not how to rule his own house, how shall he take care of the church of God?"'),
('1 Timothy', 3, 'adults', 3, 'What must deacons hold with a pure conscience?', 'The mystery of the faith', 'The keys of the kingdom', 'The scrolls of the law', 'The traditions of the elders', 'a', '1 Timothy 3:9 — "Holding the mystery of the faith in a pure conscience."'),
('1 Timothy', 3, 'adults', 4, 'What does Paul say about the wives (of deacons or deaconesses) in verse 11?', 'They must be grave, not slanderers, sober, faithful in all things', 'They should remain silent at all times', 'They should manage the church finances', 'They should teach all the women''s classes', 'a', '1 Timothy 3:11 — "Even so must their wives be grave, not slanderers, sober, faithful in all things."'),
('1 Timothy', 3, 'adults', 5, 'What do deacons who serve well purchase for themselves?', 'A good degree and great boldness in the faith which is in Christ Jesus', 'A promotion to the office of bishop', 'A financial reward from the church', 'A guaranteed place in heaven', 'a', '1 Timothy 3:13 — "For they that have used the office of a deacon well purchase to themselves a good degree, and great boldness in the faith which is in Christ Jesus."'),
('1 Timothy', 3, 'adults', 6, 'Why is Paul writing these instructions to Timothy?', 'That thou mayest know how thou oughtest to behave thyself in the house of God', 'To establish Paul''s authority over Timothy', 'To create a legal document for the church', 'To record the history of the church at Ephesus', 'a', '1 Timothy 3:15 — "But if I tarry long, that thou mayest know how thou oughtest to behave thyself in the house of God."'),
('1 Timothy', 3, 'adults', 7, 'What six-part creedal statement does Paul give about the mystery of godliness?', 'God was manifest in the flesh, justified in the Spirit, seen of angels, preached unto the Gentiles, believed on in the world, received up into glory', 'Born of a virgin, baptized in Jordan, tempted in the wilderness, crucified on Calvary, buried in a tomb, risen on the third day', 'Created the world, called Abraham, delivered Israel, gave the law, sent the prophets, established the church', 'Father almighty, Son eternal, Spirit holy, church universal, saints forgiven, life everlasting', 'a', '1 Timothy 3:16 — "God was manifest in the flesh, justified in the Spirit, seen of angels, preached unto the Gentiles, believed on in the world, received up into glory."'),
('1 Timothy', 3, 'adults', 8, 'What does Paul call the church of the living God?', 'The pillar and ground of the truth', 'The bride of Christ', 'The body of believers', 'The temple of the Holy Ghost', 'a', '1 Timothy 3:15 — "The church of the living God, the pillar and ground of the truth."');

-- ═══ 1 Timothy Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Timothy', 4, 'kids', 1, 'What does Paul say some people will do in the last times?', 'Depart from the faith (stop believing)', 'Become stronger in their faith', 'All become missionaries', 'Everyone will agree on everything', 'a', '1 Timothy 4:1 — "Now the Spirit speaketh expressly, that in the latter times some shall depart from the faith."'),
('1 Timothy', 4, 'kids', 2, 'What does Paul tell Timothy to be for other believers?', 'An example (a good role model)', 'The boss of everyone', 'The richest person', 'The quietest person', 'a', '1 Timothy 4:12 — "Be thou an example of the believers, in word, in conversation, in charity, in spirit, in faith, in purity."'),
('1 Timothy', 4, 'kids', 3, 'What is better than exercising your body?', 'Godliness (being close to God)', 'Being the fastest runner', 'Having the most toys', 'Sleeping all day', 'a', '1 Timothy 4:8 — "For bodily exercise profiteth little: but godliness is profitable unto all things."'),
-- Teens
('1 Timothy', 4, 'teens', 1, 'What will the departing ones give heed to?', 'Seducing spirits and doctrines of devils', 'The teachings of the apostles', 'The wisdom of the prophets', 'The commandments of God', 'a', '1 Timothy 4:1 — "Giving heed to seducing spirits, and doctrines of devils."'),
('1 Timothy', 4, 'teens', 2, 'What two things do the false teachers forbid?', 'Forbidding to marry and commanding to abstain from meats', 'Teaching the gospel and baptizing believers', 'Praying and giving thanks', 'Reading scripture and singing hymns', 'a', '1 Timothy 4:3 — "Forbidding to marry, and commanding to abstain from meats, which God hath created to be received with thanksgiving."'),
('1 Timothy', 4, 'teens', 3, 'What does Paul say about bodily exercise?', 'Bodily exercise profiteth little, but godliness is profitable unto all things', 'Bodily exercise is sinful', 'Bodily exercise is the most important thing', 'Bodily exercise and godliness are equal', 'a', '1 Timothy 4:8 — "For bodily exercise profiteth little: but godliness is profitable unto all things, having promise of the life that now is, and of that which is to come."'),
('1 Timothy', 4, 'teens', 4, 'What does Paul tell Timothy about his youth?', 'Let no man despise thy youth, but be thou an example of the believers', 'Wait until you are older to teach', 'Young people should stay silent in church', 'Youth disqualifies you from leadership', 'a', '1 Timothy 4:12 — "Let no man despise thy youth; but be thou an example of the believers, in word, in conversation, in charity, in spirit, in faith, in purity."'),
('1 Timothy', 4, 'teens', 5, 'What should Timothy give attendance to until Paul comes?', 'Reading, exhortation, and doctrine', 'Building construction and repairs', 'Collecting donations and tithes', 'Organizing feasts and celebrations', 'a', '1 Timothy 4:13 — "Till I come, give attendance to reading, to exhortation, to doctrine."'),
-- Adults
('1 Timothy', 4, 'adults', 1, 'How does Paul describe the conscience of the false teachers?', 'Speaking lies in hypocrisy, having their conscience seared with a hot iron', 'Having a tender and sensitive conscience', 'Having a well-informed conscience', 'Having a conscience guided by Scripture', 'a', '1 Timothy 4:2 — "Speaking lies in hypocrisy; having their conscience seared with a hot iron."'),
('1 Timothy', 4, 'adults', 2, 'How is every creature of God sanctified?', 'By the word of God and prayer', 'By ritual cleansing and sacrifice', 'By the approval of the elders', 'By abstaining from it for a period', 'a', '1 Timothy 4:4-5 — "For every creature of God is good, and nothing to be refused, if it be received with thanksgiving: For it is sanctified by the word of God and prayer."'),
('1 Timothy', 4, 'adults', 3, 'What does Paul call Timothy if he puts these things in remembrance?', 'A good minister of Jesus Christ, nourished up in the words of faith and of good doctrine', 'A great apostle equal to Paul', 'A worthy priest of the temple', 'A mighty prophet of God', 'a', '1 Timothy 4:6 — "If thou put the brethren in remembrance of these things, thou shalt be a good minister of Jesus Christ, nourished up in the words of faith and of good doctrine, whereunto thou hast attained."'),
('1 Timothy', 4, 'adults', 4, 'What should Timothy refuse?', 'Profane and old wives'' fables, and exercise himself rather unto godliness', 'All social gatherings and celebrations', 'All contact with Gentile believers', 'All food that has been offered to idols', 'a', '1 Timothy 4:7 — "But refuse profane and old wives'' fables, and exercise thyself rather unto godliness."'),
('1 Timothy', 4, 'adults', 5, 'Why do believers labour and suffer reproach?', 'Because we trust in the living God, who is the Saviour of all men, specially of those that believe', 'Because suffering earns heavenly rewards', 'Because it is punishment for past sins', 'Because all religious people must suffer', 'a', '1 Timothy 4:10 — "For therefore we both labour and suffer reproach, because we trust in the living God, who is the Saviour of all men, specially of those that believe."'),
('1 Timothy', 4, 'adults', 6, 'What gift did Timothy receive by prophecy with the laying on of hands?', 'A spiritual gift given by prophecy, with the laying on of the hands of the presbytery', 'The ability to speak in tongues', 'The power to heal the sick', 'The authority to write Scripture', 'a', '1 Timothy 4:14 — "Neglect not the gift that is in thee, which was given thee by prophecy, with the laying on of the hands of the presbytery."'),
('1 Timothy', 4, 'adults', 7, 'What does Paul tell Timothy to meditate upon and give himself wholly to?', 'These things — that his profiting may appear to all', 'Ancient philosophical texts', 'Military strategy and tactics', 'The traditions of the Pharisees', 'a', '1 Timothy 4:15 — "Meditate upon these things; give thyself wholly to them; that thy profiting may appear to all."'),
('1 Timothy', 4, 'adults', 8, 'What does Paul say Timothy will save by taking heed to himself and the doctrine?', 'Both himself and them that hear him', 'Only himself', 'Only those who are already believers', 'Only the elders of the church', 'a', '1 Timothy 4:16 — "Take heed unto thyself, and unto the doctrine; continue in them: for in doing this thou shalt both save thyself, and them that hear thee."');

-- ═══ 1 Timothy Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Timothy', 5, 'kids', 1, 'Who does Paul say the church should take care of?', 'Widows who are truly alone and in need', 'Only the richest members', 'Only the youngest members', 'Only people from other cities', 'a', '1 Timothy 5:3 — "Honour widows that are widows indeed."'),
('1 Timothy', 5, 'kids', 2, 'What should children and grandchildren do for their family first?', 'Show love at home and repay their parents', 'Leave home as soon as possible', 'Only help people outside the family', 'Wait for the church to help their parents', 'a', '1 Timothy 5:4 — "Let them learn first to shew piety at home, and to requite their parents: for that is good and acceptable before God."'),
('1 Timothy', 5, 'kids', 3, 'What does Paul say elders who lead well deserve?', 'Double honour', 'A new house', 'A golden crown', 'A long vacation', 'a', '1 Timothy 5:17 — "Let the elders that rule well be counted worthy of double honour."'),
-- Teens
('1 Timothy', 5, 'teens', 1, 'What does Paul say about someone who does not provide for his own family?', 'He hath denied the faith and is worse than an infidel', 'He is still a good believer', 'He is showing trust in God', 'He is focusing on spiritual things', 'a', '1 Timothy 5:8 — "But if any provide not for his own, and specially for those of his own house, he hath denied the faith, and is worse than an infidel."'),
('1 Timothy', 5, 'teens', 2, 'What age must a widow be to be enrolled in the church''s care?', 'Not under threescore years old (sixty)', 'At least thirty years old', 'At least forty years old', 'Any age if she is a widow', 'a', '1 Timothy 5:9 — "Let not a widow be taken into the number under threescore years old."'),
('1 Timothy', 5, 'teens', 3, 'What does Paul say about elders who labour in the word and doctrine?', 'They are worthy of double honour, especially those who labour in the word and doctrine', 'They should receive the same as everyone else', 'They need no special recognition', 'They should volunteer without any support', 'a', '1 Timothy 5:17 — "Let the elders that rule well be counted worthy of double honour, especially they who labour in the word and doctrine."'),
('1 Timothy', 5, 'teens', 4, 'What scripture does Paul quote about not muzzling the ox?', 'Thou shalt not muzzle the ox that treadeth out the corn, and the labourer is worthy of his reward', 'The ox knows his owner', 'The ox is a clean animal for sacrifice', 'The ox shall rest on the Sabbath', 'a', '1 Timothy 5:18 — "For the scripture saith, Thou shalt not muzzle the ox that treadeth out the corn. And, The labourer is worthy of his reward."'),
('1 Timothy', 5, 'teens', 5, 'What does Paul tell Timothy about laying hands on people hastily?', 'Lay hands suddenly on no man, neither be partaker of other men''s sins', 'Lay hands on everyone who asks', 'Only lay hands on the wealthy', 'Lay hands only on family members', 'a', '1 Timothy 5:22 — "Lay hands suddenly on no man, neither be partaker of other men''s sins: keep thyself pure."'),
-- Adults
('1 Timothy', 5, 'adults', 1, 'What does Paul say a widow indeed is?', 'One who is desolate, trusteth in God, and continueth in supplications and prayers night and day', 'Any woman whose husband has died', 'Only a widow with no children', 'A widow who remarries quickly', 'a', '1 Timothy 5:5 — "Now she that is a widow indeed, and desolate, trusteth in God, and continueth in supplications and prayers night and day."'),
('1 Timothy', 5, 'adults', 2, 'What does Paul say about the widow who lives in pleasure?', 'She is dead while she liveth', 'She is enjoying God''s blessings', 'She is living her best life', 'She is setting a good example', 'a', '1 Timothy 5:6 — "But she that liveth in pleasure is dead while she liveth."'),
('1 Timothy', 5, 'adults', 3, 'What does Paul say about younger widows and their first faith?', 'When they have begun to wax wanton against Christ, they will marry, having damnation because they have cast off their first faith', 'They should never remarry under any circumstances', 'They should immediately seek new husbands', 'Their first faith is always permanent', 'a', '1 Timothy 5:11-12 — "But the younger widows refuse... they will marry; Having damnation, because they have cast off their first faith."'),
('1 Timothy', 5, 'adults', 4, 'What does Paul prefer younger widows to do?', 'Marry, bear children, guide the house, and give none occasion to the adversary to speak reproachfully', 'Remain single and devote themselves entirely to prayer', 'Travel as missionaries to other churches', 'Move back to their parents'' households', 'a', '1 Timothy 5:14 — "I will therefore that the younger women marry, bear children, guide the house, give none occasion to the adversary to speak reproachfully."'),
('1 Timothy', 5, 'adults', 5, 'How should an accusation against an elder be received?', 'Not except before two or three witnesses', 'From any single accuser', 'Only from other elders', 'Only from the apostle himself', 'a', '1 Timothy 5:19 — "Against an elder receive not an accusation, but before two or three witnesses."'),
('1 Timothy', 5, 'adults', 6, 'What should be done with elders who sin?', 'Rebuke them before all, that others also may fear', 'Speak to them privately and never mention it again', 'Ignore the sin to preserve church unity', 'Immediately remove them without discussion', 'a', '1 Timothy 5:20 — "Them that sin rebuke before all, that others also may fear."'),
('1 Timothy', 5, 'adults', 7, 'What does Paul charge Timothy before God and the elect angels?', 'Observe these things without preferring one before another, doing nothing by partiality', 'Build a new meeting place for the church', 'Appoint as many elders as possible', 'Send missionaries to every Roman province', 'a', '1 Timothy 5:21 — "I charge thee before God, and the Lord Jesus Christ, and the elect angels, that thou observe these things without preferring one before another, doing nothing by partiality."'),
('1 Timothy', 5, 'adults', 8, 'What does Paul advise Timothy about his frequent infirmities?', 'Drink no longer water, but use a little wine for thy stomach''s sake and thine often infirmities', 'Fast and pray until healed', 'See a Greek physician immediately', 'Accept suffering as God''s will without remedy', 'a', '1 Timothy 5:23 — "Drink no longer water, but use a little wine for thy stomach''s sake and thine often infirmities."');

-- ═══ 1 Timothy Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Timothy', 6, 'kids', 1, 'What does Paul say is great gain?', 'Godliness with contentment', 'Having lots of money', 'Being the most popular person', 'Winning every competition', 'a', '1 Timothy 6:6 — "But godliness with contentment is great gain."'),
('1 Timothy', 6, 'kids', 2, 'What does Paul say about the love of money?', 'It is the root of all evil', 'It is the best thing in life', 'It makes you happy forever', 'It is a sign of God''s blessing', 'a', '1 Timothy 6:10 — "For the love of money is the root of all evil."'),
('1 Timothy', 6, 'kids', 3, 'What good fight does Paul tell Timothy to fight?', 'The good fight of faith', 'A fight with swords and shields', 'A wrestling match', 'A running race', 'a', '1 Timothy 6:12 — "Fight the good fight of faith."'),
-- Teens
('1 Timothy', 6, 'teens', 1, 'What did we bring into this world and what can we carry out?', 'We brought nothing in, and it is certain we can carry nothing out', 'We brought our talents and will take our achievements', 'We brought nothing but will carry out our memories', 'We brought our souls and will carry out our rewards', 'a', '1 Timothy 6:7 — "For we brought nothing into this world, and it is certain we can carry nothing out."'),
('1 Timothy', 6, 'teens', 2, 'What happens to people who want to be rich?', 'They fall into temptation and a snare and many foolish and hurtful lusts that drown men in destruction and perdition', 'They always succeed and are blessed by God', 'They become generous and charitable', 'They find true happiness and peace', 'a', '1 Timothy 6:9 — "But they that will be rich fall into temptation and a snare, and into many foolish and hurtful lusts, which drown men in destruction and perdition."'),
('1 Timothy', 6, 'teens', 3, 'What should Timothy flee from and what should he follow after?', 'Flee the love of money; follow after righteousness, godliness, faith, love, patience, meekness', 'Flee all people; follow only the apostles', 'Flee all cities; follow the wilderness path', 'Flee all knowledge; follow only feelings', 'a', '1 Timothy 6:11 — "But thou, O man of God, flee these things; and follow after righteousness, godliness, faith, love, patience, meekness."'),
('1 Timothy', 6, 'teens', 4, 'What good confession did Christ witness before Pontius Pilate?', 'A good confession — Timothy should keep the commandment without spot until the appearing of the Lord Jesus Christ', 'That he was the King of the Jews', 'That he came to destroy Rome', 'That he would return in three days', 'a', '1 Timothy 6:13 — "I give thee charge in the sight of God... and before Christ Jesus, who before Pontius Pilate witnessed a good confession."'),
('1 Timothy', 6, 'teens', 5, 'What should the rich in this world NOT be?', 'Highminded, nor trust in uncertain riches, but in the living God who giveth us richly all things to enjoy', 'Generous with their money', 'Involved in church activities', 'Friends with poor people', 'a', '1 Timothy 6:17 — "Charge them that are rich in this world, that they be not highminded, nor trust in uncertain riches, but in the living God, who giveth us richly all things to enjoy."'),
-- Adults
('1 Timothy', 6, 'adults', 1, 'What does Paul say about servants and their masters in verse 1?', 'Servants should count their own masters worthy of all honour, that the name of God and his doctrine be not blasphemed', 'Servants should demand their freedom in Christ', 'Servants have no obligations to unbelieving masters', 'Masters and servants are equal in all social matters', 'a', '1 Timothy 6:1 — "Let as many servants as are under the yoke count their own masters worthy of all honour, that the name of God and his doctrine be not blasphemed."'),
('1 Timothy', 6, 'adults', 2, 'What does Paul say about those who teach differently and do not consent to sound words?', 'He is proud, knowing nothing, doting about questions and strifes of words, whereof cometh envy, strife, railings, evil surmisings', 'He is a mature believer with a different perspective', 'He is being led by a different spiritual gift', 'He should be given more time to come to the truth', 'a', '1 Timothy 6:3-4 — "If any man teach otherwise, and consent not to wholesome words, even the words of our Lord Jesus Christ, and to the doctrine which is according to godliness; He is proud, knowing nothing."'),
('1 Timothy', 6, 'adults', 3, 'What do some suppose gain is?', 'Godliness — thinking religion is a means of financial gain; from such withdraw thyself', 'A fair and legitimate business practice', 'A sign of God''s favour and blessing', 'The natural result of hard work', 'a', '1 Timothy 6:5 — "Perverse disputings of men of corrupt minds, and destitute of the truth, supposing that gain is godliness: from such withdraw thyself."'),
('1 Timothy', 6, 'adults', 4, 'What did some who coveted after money do?', 'They erred from the faith and pierced themselves through with many sorrows', 'They built large and prosperous churches', 'They funded many missionary trips', 'They became the most respected church leaders', 'a', '1 Timothy 6:10 — "Which while some coveted after, they have erred from the faith, and pierced themselves through with many sorrows."'),
('1 Timothy', 6, 'adults', 5, 'What titles does Paul give God in verses 15-16?', 'The blessed and only Potentate, the King of kings, and Lord of lords, who only hath immortality, dwelling in the light which no man can approach unto', 'The Ancient of Days, the Judge of all the earth', 'The God of Abraham, Isaac, and Jacob', 'The Lord of hosts, the Maker of heaven and earth', 'a', '1 Timothy 6:15-16 — "The blessed and only Potentate, the King of kings, and Lord of lords; Who only hath immortality, dwelling in the light which no man can approach unto."'),
('1 Timothy', 6, 'adults', 6, 'What does Paul tell the rich to be rich in?', 'Good works, ready to distribute, willing to communicate', 'Gold, silver, and precious stones', 'Land, houses, and possessions', 'Theological knowledge and debate skills', 'a', '1 Timothy 6:18 — "That they do good, that they be rich in good works, ready to distribute, willing to communicate."'),
('1 Timothy', 6, 'adults', 7, 'What does Paul tell Timothy to keep and avoid?', 'Keep that which is committed to thy trust, avoiding profane and vain babblings, and oppositions of science falsely so called', 'Keep the Jewish traditions and avoid Gentile customs', 'Keep the peace and avoid all confrontation', 'Keep his wealth and avoid poverty', 'a', '1 Timothy 6:20 — "O Timothy, keep that which is committed to thy trust, avoiding profane and vain babblings, and oppositions of science falsely so called."'),
('1 Timothy', 6, 'adults', 8, 'What happened to some who professed "science falsely so called"?', 'They erred concerning the faith', 'They became great scholars', 'They discovered important truths', 'They were promoted in the church', 'a', '1 Timothy 6:21 — "Which some professing have erred concerning the faith. Grace be with thee. Amen."');
